SELECT count(*) FROM title, kind_type, movie_companies, cast_info, name, company_type, company_name, aka_name WHERE title.kind_id = kind_type.id AND movie_companies.movie_id = title.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id AND movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id AND aka_name.person_id = name.id;